// // This module decrements its value on each positive clock edge and resets to 255 when the reset input is asserted.
module top_module(
  input clk,
  input reset,
  output reg [7:0] count
);always @(posedge clk) begin
    if (reset) begin
      count <= 8'b0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
